t.script:
            (function() {
                var total = document.querySelectorAll('.lx-exercise-card').length;
                var answered = 0;
                var rightCount = 0;

                document.querySelectorAll('.lx-exercise-card').forEach(function(card) {
                    var correctAnswer = card.dataset.answer;
                    var hint = card.dataset.hint || '';
                    var feedback = card.querySelector('.lx-feedback');
                    var buttons = card.querySelectorAll('.lx-choice-btn');

                    buttons.forEach(function(btn) {
                        btn.addEventListener('click', function() {
                            if (card.dataset.done) return;
                            card.dataset.done = '1';

                            var chosen = (btn.dataset.value || '').trim();
                            var isCorrect = chosen === (correctAnswer || '').trim();
                            if (isCorrect) rightCount++;
                            answered++;

                            buttons.forEach(function(b) {
                                b.disabled = true;
                                if (b.dataset.value === correctAnswer) {
                                    b.style.cssText = 'background:rgba(34,197,94,0.2);color:#4ade80;border:1px solid rgba(34,197,94,0.5);border-radius:8px;font-size:0.9rem;padding:6px 16px;font-weight:600';
                                } else if (b === btn && !isCorrect) {
                                    b.style.cssText = 'background:rgba(239,68,68,0.15);color:#f87171;border:1px solid rgba(239,68,68,0.4);border-radius:8px;font-size:0.9rem;padding:6px 16px;text-decoration:line-through';
                                }
                            });

                            card.style.borderColor = isCorrect ? 'rgba(34,197,94,0.4)' : 'rgba(239,68,68,0.35)';

                            feedback.classList.remove('d-none');
                            if (isCorrect) {
                                feedback.innerHTML = '✓ Correct!';
                            } else {
                                feedback.innerHTML = '✗ Incorrect. The correct answer is: ' + correctAnswer + '';
                            }
                            if (hint && !isCorrect) {
                                feedback.innerHTML += '
💡 ' + hint + '';
                            }

                            if (answered === total) {
                                document.getElementById('lx-score-text').textContent = rightCount + ' / ' + total + ' correct';
                                document.getElementById('lx-score-summary').classList.remove('d-none');
                                document.getElementById('lx-score-summary').scrollIntoView({behavior:'smooth', block:'center'});
                                if (rightCount > 0) {
                                    var csrfTok = (typeof odoo !== 'undefined' ? odoo.csrf_token : '');
                                    fetch('/my/grammar-practice/score', {
                                        method: 'POST',
                                        credentials: 'same-origin',
                                        headers: {
                                            'Content-Type': 'application/json',
                                            'X-CSRF-Token': csrfTok
                                        },
                                        body: JSON.stringify({
                                            jsonrpc: '2.0',
                                            method: 'call',
                                            id: 1,
                                            params: {correct_count: rightCount}
                                        })
                                    })
                                    .then(function(r) { return r.json(); })
                                    .then(function(data) {
                                        var xp = (data.result || {}).xp_gained || 0;
                                        if (xp > 0) {
                                            document.getElementById('lx-xp-amount').textContent = xp;
                                            document.getElementById('lx-xp-gained').classList.remove('d-none');
                                        }
                                    })
                                    .catch(function(err) { console.warn('XP award failed:', err); });
                                }
                            }
                        });
                    });
                });
            })();
